import { _decorator, Component, AudioClip, AudioSource } from 'cc';

const { ccclass, property } = _decorator;

@ccclass('AudioManager')
export class AudioManager extends Component {
    static instance: AudioManager = null;
    
    @property(AudioClip)
    bgmClip: AudioClip = null;
    
    @property(AudioClip)
    clickClip: AudioClip = null;
    
    @property(AudioClip)
    successClip: AudioClip = null;
    
    @property(AudioClip)
    failClip: AudioClip = null;
    
    private bgmSource: AudioSource = null;
    private sfxSource: AudioSource = null;
    private isMuted: boolean = false;
    
    onLoad() {
        if (AudioManager.instance === null) {
            AudioManager.instance = this;
        }
    }
    
    static getInstance(): AudioManager {
        return AudioManager.instance;
    }
    
    playBGM() {
        if (this.isMuted || !this.bgmClip) return;
        
        if (!this.bgmSource) {
            this.bgmSource = this.node.addComponent(AudioSource);
            this.bgmSource.clip = this.bgmClip;
            this.bgmSource.loop = true;
        }
        
        this.bgmSource.play();
    }
    
    stopBGM() {
        if (this.bgmSource) {
            this.bgmSource.stop();
        }
    }
    
    playSFX(clip: AudioClip) {
        if (this.isMuted || !clip) return;
        
        if (!this.sfxSource) {
            this.sfxSource = this.node.addComponent(AudioSource);
        }
        
        this.sfxSource.playOneShot(clip);
    }
    
    playClick() {
        this.playSFX(this.clickClip);
    }
    
    playSuccess() {
        this.playSFX(this.successClip);
    }
    
    playFail() {
        this.playSFX(this.failClip);
    }
    
    setMute(muted: boolean) {
        this.isMuted = muted;
        if (muted) {
            this.stopBGM();
        } else {
            this.playBGM();
        }
    }
    
    isMusicMuted(): boolean {
        return this.isMuted;
    }
}
